patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..b2d8eb8d75f1 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -567,6 +567,17 @@ bool llvm::isValidAssumeForContext(const Instruction *Inv,
 // so the extra compile time may not be worth it, but possibly a second API
 // should be created for use outside of loops.
 static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
+  // v == y and y is non-zero implies v != 0.
+  if (Pred == ICmpInst::ICMP_EQ) {
+    if (const auto *I = dyn_cast<Instruction>(RHS)) {
+      if (isKnownNonZero(RHS, SimplifyQuery(I->getDataLayout()), 0))
+        return true;
+    } else if (const auto *A = dyn_cast<Argument>(RHS)) {
+      if (isKnownNonZero(RHS, SimplifyQuery(A->getParent()->getParent()->getDataLayout()), 0))
+        return true;
+    }
+  }
+
   // v u> y implies v != 0.
   if (Pred == ICmpInst::ICMP_UGT)
     return true;
@@ -3699,10 +3710,11 @@ static bool isModifyingBinopOfNonZero(const Value *V1, const Value *V2,
     [[fallthrough]];
   case Instruction::Xor:
   case Instruction::Add:
+  case Instruction::Sub:
     Value *Op = nullptr;
     if (V2 == BO->getOperand(0))
       Op = BO->getOperand(1);
-    else if (V2 == BO->getOperand(1))
+    else if (V2 == BO->getOperand(1) && BO->getOpcode() != Instruction::Sub)
       Op = BO->getOperand(0);
     else
       return false;

